import { type CSSProperties, type ReactNode } from 'react';

import { Flex } from '../../../../../layouts/flex/Flex.js';
import {
  AXIS_LABEL_HEIGHT,
  X_AXES_LABEL_OFFSET,
  X_AXES_TICK_LINE_OFFSET,
  Y_AXES_TICK_LINE_OFFSET,
  Y_AXIS_LABEL_OFFSET,
} from '../constants.js';

export interface DivAxisProps {
  children: ReactNode;
  ticks: string[];
  divAxisStyle?: object;
  label?: string;
  isTickVertical?: boolean;
  isTickRotated?: boolean;
}

/**
 * We have discrepancies between Browsers engines where
 * we need to specify the minimum content for the label element
 */
const TICK_MIN_WIDTH = 8;
const TICK_MIN_HEIGHT = 12;

const getDivContainerAxisStyle = (
  isTickVertical: boolean,
  isTickRotated: boolean,
) => {
  let tickStyle: CSSProperties;
  let labelStyle: CSSProperties;

  const rotatedTextStyle: CSSProperties = {
    writingMode: 'vertical-rl',
  };

  if (isTickVertical) {
    tickStyle = {
      marginTop: X_AXES_TICK_LINE_OFFSET,
      minHeight: isTickRotated ? TICK_MIN_HEIGHT : 0,
      whiteSpace: 'nowrap',
      overflow: 'hidden',
      ...(isTickRotated ? rotatedTextStyle : {}),
    };
    labelStyle = {
      marginTop: X_AXES_LABEL_OFFSET,
      whiteSpace: 'nowrap',
      overflow: 'hidden',
    };
  } else {
    tickStyle = {
      marginRight: Y_AXES_TICK_LINE_OFFSET,
      minWidth: TICK_MIN_WIDTH,
      whiteSpace: 'nowrap',
    };
    labelStyle = {
      marginRight: Y_AXIS_LABEL_OFFSET,
      minWidth: AXIS_LABEL_HEIGHT,
      whiteSpace: 'nowrap',
      ...rotatedTextStyle,
    };
  }

  return { tickStyle, labelStyle };
};

/**
 * This component creates a layout containing an SVG and HTML version of the axis.
 * The SVG axis should be positioned absolutely within the wrapper component.
 * Below it, we need to generate an identical HTML axis with hidden visibility.
 * By doing this, we can obtain the size of the HTML axis and use it to dynamically position the SVG axis instead
 * of performing complex calculations. The HTML axis size allows us to use CSS Grid with a min-max content approach
 * and manage plots more efficiently.
 */
export const DivAxisWrapper = ({
  ticks,
  label,
  isTickVertical = false,
  isTickRotated = false,
  divAxisStyle = {},
  children,
}: DivAxisProps) => {
  const { tickStyle, labelStyle } = getDivContainerAxisStyle(
    isTickVertical,
    isTickRotated,
  );

  const containerAxisStyle: CSSProperties = {
    position: 'relative',
    /* A combination of pointer Events is needed here and in visibleSVGAxisStyle to allow the correct functioning with the resizer in the bottom legend when the tick labels are rotated and truncated (edge case) */
    pointerEvents: 'none',
  };
  const visibleSvgAxisStyle: CSSProperties = {
    position: 'absolute',
    pointerEvents: 'visible',
  };
  const hiddenDivAxisStyle: CSSProperties = {
    visibility: 'hidden',
    ...divAxisStyle,
  };

  return (
    <div style={containerAxisStyle}>
      <div style={visibleSvgAxisStyle}>{children}</div>
      <Flex
        style={hiddenDivAxisStyle}
        flexDirection={isTickVertical ? 'column-reverse' : 'row'}
        gap={0}
      >
        {label && <span style={labelStyle}>{label}</span>}
        <Flex flexDirection={isTickVertical ? 'row' : 'column'}>
          {ticks?.map((tick, index) => (
            <span style={tickStyle} key={`${index}_${tick}`}>
              {tick}
            </span>
          ))}
        </Flex>
      </Flex>
    </div>
  );
};

DivAxisWrapper['displayName'] = 'DivAxisWrapper';
